@Composable
private fun StatItem(num: String, title: String, subtitle: String) {
    Column(horizontalAlignment = Alignment.CenterHorizontally) {
        Text(num, fontSize = 24.sp, fontWeight = FontWeight.Bold, color = Color(0xFF00D4FF))
        Text(title, fontSize = 12.sp, fontWeight = FontWeight.SemiBold, color = Color.White)
        Text(subtitle, fontSize = 11.sp, color = Color(0xFF7A9BB5))
    }
}

@Composable
private fun SectionHeader(title: String, subtitle: String) {
    Column(modifier = Modifier.padding(horizontal = 24.dp, vertical = 24.dp)) {
        Text(
            title,
            fontSize = 28.sp,
            fontWeight = FontWeight.Bold,
            color = Color.White
        )
        Text(
            subtitle,
            fontSize = 16.sp,
            color = Color(0xFF7A9BB5),
            modifier = Modifier.padding(top = 8.dp)
        )
    }
}

@Composable
private fun ModCard(modifier: Modifier, icon: String, title: String, description: String) {
    Card(
        modifier = modifier.clickable { },
        shape = RoundedCornerShape(14.dp),
        colors = CardDefaults.cardColors(containerColor = Color(0xFF0F1E35)),
        border = androidx.compose.foundation.BorderStroke(1.dp, Color.White.copy(alpha = 0.08f))
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            Text(icon, fontSize = 24.sp)
            Spacer(modifier = Modifier.height(8.dp))
            Text(title, fontWeight = FontWeight.SemiBold, fontSize = 15.sp, color = Color.White)
            Text(description, fontSize = 13.sp, color = Color(0xFF7A9BB5), lineHeight = 18.sp)
        }
    }
}

@Composable
private fun PrecioCard(
    plan: String, precio: String, periodo: String,
    description: String, features: List<String>, isFeatured: Boolean
) {
    Card(
        shape = RoundedCornerShape(18.dp),
        colors = CardDefaults.cardColors(
            containerColor = if (isFeatured) Color(0xFF1A3565).copy(alpha = 0.5f) else Color(0xFF0F1E35)
        ),
        border = androidx.compose.foundation.BorderStroke(
            width = if (isFeatured) 2.dp else 1.dp,
            color = if (isFeatured) Accent else Color.White.copy(alpha = 0.08f)
        )
    ) {
        Column(modifier = Modifier.padding(24.dp)) {
            if (isFeatured) {
                Surface(
                    shape = RoundedCornerShape(100.dp),
                    color = Accent,
                    modifier = Modifier.padding(bottom = 12.dp)
                ) {
                    Text("Más popular", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.SemiBold,
                        modifier = Modifier.padding(horizontal = 12.dp, vertical = 4.dp))
                }
            }
            Text(plan, fontSize = 13.sp, color = Color(0xFF7A9BB5), fontWeight = FontWeight.Medium)
            Row(verticalAlignment = Alignment.Bottom, modifier = Modifier.padding(vertical = 8.dp)) {
                Text(precio, fontSize = 32.sp, fontWeight = FontWeight.Bold, color = Color.White)
                Text(periodo, fontSize = 14.sp, color = Color(0xFF7A9BB5), modifier = Modifier.padding(bottom = 4.dp))
            }
            Text(description, fontSize = 13.sp, color = Color(0xFF7A9BB5), modifier = Modifier.padding(bottom = 16.dp))
            features.forEach { feature ->
                Row(modifier = Modifier.padding(vertical = 4.dp), verticalAlignment = Alignment.CenterVertically) {
                    Text("✓", color = Color(0xFF00E5A0), fontWeight = FontWeight.Bold, fontSize = 14.sp)
                    Spacer(modifier = Modifier.width(8.dp))
                    Text(feature, fontSize = 14.sp, color = Color.White)
                }
            }
            Spacer(modifier = Modifier.height(16.dp))
            Button(
                onClick = { },
                modifier = Modifier.fillMaxWidth().height(44.dp),
                colors = ButtonDefaults.buttonColors(
                    containerColor = if (isFeatured) Accent else Color.Transparent
                ),
                border = if (!isFeatured) androidx.compose.foundation.BorderStroke(1.dp, Color.White.copy(alpha = 0.2f)) else null,
                shape = RoundedCornerShape(10.dp)
            ) {
                Text("Comenzar", fontWeight = FontWeight.SemiBold)
            }
        }
    }
}

private data class ModuloData(val icon: String, val title: String, val description: String)

